import 'dart:convert'; import 'package:http/http.dart' as http; void main() async { var regRes = await http.post(Uri.parse('http://localhost:8080/api/auth/register/phone'), headers: {'Content-Type': 'application/json'}, body: jsonEncode({'phoneNumber': '+998970504203', 'password': 'password123'})); print('Reg: ' + regRes.statusCode.toString() + ' ' + regRes.body); if (regRes.statusCode != 200) return; var token = jsonDecode(regRes.body)['accessToken']; var meRes = await http.get(Uri.parse('http://localhost:8080/api/users/me'), headers: {'Authorization': 'Bearer ' + token}); print('Me: ' + meRes.statusCode.toString() + ' ' + meRes.body); }
